function Stars({ n }) {
  return <div style={{display:"flex",gap:2,marginBottom:8}}>{Array.from({length:n}).map((_,i)=><span key={i} style={{color:"#e07b00",fontSize:14}}>&#9733;</span>)}</div>;
}

function FadeIn({ children, delay = 0 }) {
  const ref = useRef();
  const [show, setShow] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setShow(true); }, { threshold: 0.1 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} style={{ opacity: show?1:0, transform: show?"translateY(0)":"translateY(22px)", transition: `opacity 0.6s ease ${delay}s, transform 0.6s ease ${delay}s` }}>
      {children}
    </div>
  );
}

function PhotoBanner({ src, alt, caption, overlay = "rgba(0,0,0,0.35)" }) {
  const ref = useRef();
  const [show, setShow] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setShow(true); }, { threshold: 0.1 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} style={{ position:"relative", height:280, overflow:"hidden", opacity:show?1:0, transition:"opacity 1s ease" }}>
      <img src={src} alt={alt} style={{ width:"100%", height:"100%", objectFit:"cover", objectPosition:"center", transform:show?"scale(1)":"scale(1.06)", transition:"transform 1.4s ease" }} />
      <div style={{ position:"absolute", inset:0, background:overlay }} />
      {caption && (
        <div style={{ position:"absolute", bottom:24, left:0, right:0, textAlign:"center", color:"rgba(255,255,255,0.9)", fontFamily:"'Playfair Display',serif", fontStyle:"italic", fontSize:18, letterSpacing:"0.04em", textShadow:"0 2px 8px rgba(0,0,0,0.5)" }}>
          {caption}
        </div>
      )}
    </div>
  );
}


